        final androidInfo = await _deviceInfo.androidInfo;
        fingerprint = '${androidInfo.id}_${androidInfo.androidId}_${androidInfo.model}';
      } else if (Platform.isIOS) {
        final iosInfo = await _deviceInfo.iosInfo;
        fingerprint = '${iosInfo.identifierForVendor}_${iosInfo.model}_${iosInfo.systemVersion}';
      }
      _deviceId = sha256.convert(utf8.encode(fingerprint)).toString();
