class PaymentEncryption {
  static String encryptPaymentData(Map<String, dynamic> data, String publicKey) {
    final jsonData = json.encode(data);
    final bytes = utf8.encode(jsonData);
    final timestamp = DateTime.now().millisecondsSinceEpoch.toString();
    final nonce = _generateNonce();
    
    final payload = {
      'data': base64.encode(bytes),
      'timestamp': timestamp,
      'nonce': nonce,
    };
    
    return base64.encode(utf8.encode(json.encode(payload)));
  }

  static String _generateNonce() {
    final random = DateTime.now().microsecondsSinceEpoch;
    return sha256.convert(utf8.encode(random.toString())).toString().substring(0, 16);
  }

  static String generateHMAC(String data, String secret) {
    final key = utf8.encode(secret);
    final bytes = utf8.encode(data);
    final hmac = Hmac(sha256, key);
    final digest = hmac.convert(bytes);
    return digest.toString();
  }
}

