class StripePaymentGateway implements PaymentGateway {
  final PaymentGatewayConfig config;
  final String _baseUrl = 'https://api.stripe.com/v1';

  StripePaymentGateway(this.config);

  @override
  Future<PaymentTransaction> processPayment({
    required String userId,
    required double amount,
    required String currency,
    required Map<String, dynamic> paymentMethod,
    Map<String, dynamic>? metadata,
  }) async {
    await DeviceIntegrityChecker().validateDeviceIntegrity();

    final transactionId = _generateTransactionId();
    final timestamp = DateTime.now();

    try {
      final encryptedData = PaymentEncryption.encryptPaymentData({
        'amount': (amount * 100).toInt(),
        'currency': currency,
        'payment_method': paymentMethod,
        'metadata': metadata ?? {},
      }, config.apiKey);

      final response = await http.post(
        Uri.parse('$_baseUrl/payment_intents'),
        headers: {
          'Authorization': 'Bearer ${config.apiKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
          'X-Device-ID': DeviceIntegrityChecker().deviceId ?? 'unknown',
        },
        body: {
          'amount': (amount * 100).toInt().toString(),
          'currency': currency,
          'payment_method': paymentMethod['id'],
          'confirm': 'true',
          'metadata[user_id]': userId,
          'metadata[transaction_id]': transactionId,
        },
      ).timeout(config.timeout);

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        
        return PaymentTransaction(
          id: transactionId,
          userId: userId,
          amount: amount,
          currency: currency,
          provider: PaymentProvider.stripe,
          status: _mapStripeStatus(data['status']),
          timestamp: timestamp,
          metadata: metadata ?? {},
          receiptData: json.encode(data),
          signature: PaymentEncryption.generateHMAC(
            json.encode(data),
            config.apiKey,
          ),
        );
      } else {
        throw PaymentSecurityException(
          'Payment processing failed: ${response.body}',
          'PAYMENT_FAILED'
        );
      }
    } catch (e) {
      return PaymentTransaction(
        id: transactionId,
        userId: userId,
        amount: amount,
        currency: currency,
        provider: PaymentProvider.stripe,
        status: TransactionStatus.failed,
        timestamp: timestamp,
        metadata: {'error': e.toString()},
      );
    }
  }

  @override
  Future<bool> verifyTransaction(String transactionId) async {
    try {
      final response = await http.get(
        Uri.parse('$_baseUrl/payment_intents/$transactionId'),
        headers: {
          'Authorization': 'Bearer ${config.apiKey}',
        },
      ).timeout(config.timeout);

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        return data['status'] == 'succeeded';
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  @override
  Future<PaymentTransaction> refundTransaction(String transactionId, {double? amount}) async {
    try {
      final response = await http.post(
        Uri.parse('$_baseUrl/refunds'),
        headers: {
          'Authorization': 'Bearer ${config.apiKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'payment_intent': transactionId,
          if (amount != null) 'amount': (amount * 100).toInt().toString(),
        },
      ).timeout(config.timeout);

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        return PaymentTransaction(
          id: data['id'],
          userId: '',
          amount: amount ?? 0,
          currency: data['currency'],
          provider: PaymentProvider.stripe,
          status: TransactionStatus.refunded,
          timestamp: DateTime.now(),
          receiptData: json.encode(data),
        );
      } else {
        throw PaymentSecurityException('Refund failed', 'REFUND_FAILED');
      }
    } catch (e) {
      rethrow;
    }
  }

  @override
  Future<void> cancelTransaction(String transactionId) async {
    try {
      await http.post(
        Uri.parse('$_baseUrl/payment_intents/$transactionId/cancel'),
        headers: {
          'Authorization': 'Bearer ${config.apiKey}',
        },
      ).timeout(config.timeout);
    } catch (e) {
      throw PaymentSecurityException('Cancellation failed', 'CANCEL_FAILED');
    }
  }

  TransactionStatus _mapStripeStatus(String status) {
    switch (status) {
      case 'succeeded':
        return TransactionStatus.completed;
      case 'processing':
        return TransactionStatus.processing;
      case 'requires_payment_method':
      case 'requires_confirmation':
        return TransactionStatus.pending;
      case 'canceled':
        return TransactionStatus.cancelled;
      default:
        return TransactionStatus.failed;
    }
  }

  String _generateTransactionId() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final random = timestamp.hashCode;
    return 'txn_${timestamp}_$random';
  }
}

class InAppPurchaseManager {
  static final InAppPurchaseManager _instance = InAppPurchaseManager._internal();
  factory InAppPurchaseManager() => _instance;
  InAppPurchaseManager._internal();

  final InAppPurchase _iap = InAppPurchase.instance;
  StreamSubscription<List<PurchaseDetails>>? _subscription;
  final StreamController<PaymentTransaction> _transactionController = 
      StreamController<PaymentTransaction>.broadcast();

  Stream<PaymentTransaction> get transactionStream => _transactionController.stream;

  Future<void> initialize() async {
    await DeviceIntegrityChecker().initialize();
    await DeviceIntegrityChecker().validateDeviceIntegrity();

    final available = await _iap.isAvailable();
    if (!available) {
      throw PaymentSecurityException(
        'In-app purchases not available',
        'IAP_UNAVAILABLE'
      );
    }

    if (Platform.isIOS) {
      final iosPlatform = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await iosPlatform.setDelegate(PaymentQueueDelegate());
    }

    _subscription = _iap.purchaseStream.listen(
      _handlePurchaseUpdates,
      onError: (error) {
        _transactionController.addError(error);
      },
    );
  }

  Future<List<ProductDetails>> getProducts(Set<String> productIds) async {
    final response = await _iap.queryProductDetails(productIds);
    
    if (response.error != null) {
      throw PaymentSecurityException(
        'Failed to fetch products: ${response.error}',
        'PRODUCT_FETCH_FAILED'
      );
    }

    return response.productDetails;
  }

  Future<void> purchaseProduct(ProductDetails product, {String? userId}) async {
    await DeviceIntegrityChecker().validateDeviceIntegrity();

    final purchaseParam = PurchaseParam(
      productDetails: product,
      applicationUserName: userId,
    );

    try {
      if (product.id.contains('subscription')) {
        await _iap.buyNonConsumable(purchaseParam: purchaseParam);
      } else {
        await _iap.buyConsumable(purchaseParam: purchaseParam);
      }
    } catch (e) {
      throw PaymentSecurityException(
        'Purchase failed: $e',
        'PURCHASE_FAILED'
      );
    }
  }

  Future<void> restorePurchases() async {
    await DeviceIntegrityChecker().validateDeviceIntegrity();
    
    try {
      await _iap.restorePurchases();
    } catch (e) {
      throw PaymentSecurityException(
        'Restore failed: $e',
        'RESTORE_FAILED'
      );
    }
  }

  void _handlePurchaseUpdates(List<PurchaseDetails> purchases) async {
    for (final purchase in purchases) {
      await _processPurchase(purchase);
    }
  }

  Future<void> _processPurchase(PurchaseDetails purchase) async {
    if (purchase.status == PurchaseStatus.pending) {
      _transactionController.add(PaymentTransaction(
        id: purchase.purchaseID ?? 'unknown',
        userId: '',
        amount: 0,
        currency: 'USD',
        provider: PaymentProvider.inAppPurchase,
        status: TransactionStatus.pending,
        timestamp: DateTime.now(),
      ));
    } else if (purchase.status == PurchaseStatus.purchased ||
               purchase.status == PurchaseStatus.restored) {
      
      final verified = await _verifyPurchase(purchase);
      
      if (verified) {
        _transactionController.add(PaymentTransaction(
          id: purchase.purchaseID ?? 'unknown',
          userId: '',
          amount: 0,
          currency: 'USD',
          provider: PaymentProvider.inAppPurchase,
          status: TransactionStatus.completed,
          timestamp: DateTime.now(),
          receiptData: purchase.verificationData.serverVerificationData,
          signature: purchase.verificationData.localVerificationData,
        ));

        if (purchase.pendingCompletePurchase) {
          await _iap.completePurchase(purchase);
        }
      } else {
        throw PaymentSecurityException(
          'Purchase verification failed',
          'VERIFICATION_FAILED'
        );
      }
    } else if (purchase.status == PurchaseStatus.error) {
      _transactionController.add(PaymentTransaction(
        id: purchase.purchaseID ?? 'unknown',
        userId: '',
        amount: 0,
        currency: 'USD',
        provider: PaymentProvider.inAppPurchase,
        status: TransactionStatus.failed,
        timestamp: DateTime.now(),
        metadata: {'error': purchase.error?.message ?? 'Unknown error'},
      ));
    }
  }

  Future<bool> _verifyPurchase(PurchaseDetails purchase) async {
    try {
      final receiptData = purchase.verificationData.serverVerificationData;
      final signature = purchase.verificationData.localVerificationData;
      
      if (Platform.isAndroid) {
        return await _verifyAndroidPurchase(receiptData, signature);
      } else if (Platform.isIOS) {
        return await _verifyIOSPurchase(receiptData);
      }
      
      return false;
    } catch (e) {
      return false;
    }
  }

  Future<bool> _verifyAndroidPurchase(String receiptData, String signature) async {
    return true;
  }

  Future<bool> _verifyIOSPurchase(String receiptData) async {
    return true;
  }

  void dispose() {
    _subscription?.cancel();
    _transactionController.close();
  }
}

