class BiometricAuthenticator {
  static final LocalAuthentication _auth = LocalAuthentication();

  static Future<bool> canAuthenticate() async {
    try {
      return await _auth.canCheckBiometrics && await _auth.isDeviceSupported();
    } catch (e) {
      return false;
    }
  }

  static Future<bool> authenticate({
    required String reason,
    bool biometricOnly = false,
  }) async {
    try {
      return await _auth.authenticate(
        localizedReason: reason,
        options: AuthenticationOptions(
          biometricOnly: biometricOnly,
          stickyAuth: true,
        ),
      );
    } catch (e) {
      return false;
    }
  }
}

class PaymentProcessor {
  final Map<PaymentProvider, PaymentGateway> _gateways = {};
  final InAppPurchaseManager _iapManager = InAppPurchaseManager();
  final StreamController<PaymentTransaction> _transactionController = 
      StreamController<PaymentTransaction>.broadcast();

  Stream<PaymentTransaction> get transactionStream => _transactionController.stream;

  Future<void> initialize({
    PaymentGatewayConfig? stripeConfig,
    PaymentGatewayConfig? paypalConfig,
  }) async {
    await DeviceIntegrityChecker().initialize();

    if (stripeConfig != null) {
      _gateways[PaymentProvider.stripe] = StripePaymentGateway(stripeConfig);
    }

    await _iapManager.initialize();
    _iapManager.transactionStream.listen((transaction) {
      _transactionController.add(transaction);
    });
  }

  Future<PaymentTransaction> processPayment({
    required PaymentProvider provider,
    required String userId,
    required double amount,
    required String currency,
    required Map<String, dynamic> paymentMethod,
    Map<String, dynamic>? metadata,
    bool requireBiometric = true,
  }) async {
    await DeviceIntegrityChecker().validateDeviceIntegrity();

    if (requireBiometric) {
      final canAuth = await BiometricAuthenticator.canAuthenticate();
      if (canAuth) {
        final authenticated = await BiometricAuthenticator.authenticate(
          reason: 'Authenticate to complete payment of $amount $currency',
        );
        
        if (!authenticated) {
          throw PaymentSecurityException(
            'Biometric authentication required',
            'AUTH_REQUIRED'
          );
        }
      }
    }

    final gateway = _gateways[provider];
    if (gateway == null) {
      throw PaymentSecurityException(
        'Payment provider not configured',
        'PROVIDER_NOT_CONFIGURED'
      );
    }

    final transaction = await gateway.processPayment(
      userId: userId,
      amount: amount,
      currency: currency,
      paymentMethod: paymentMethod,
      metadata: metadata,
    );

    await _storeTransaction(transaction);
    _transactionController.add(transaction);

    return transaction;
  }

  Future<void> purchaseProduct(String productId, {String? userId}) async {
    final products = await _iapManager.getProducts({productId});
    
    if (products.isEmpty) {
      throw PaymentSecurityException(
        'Product not found',
        'PRODUCT_NOT_FOUND'
      );
    }

    await _iapManager.purchaseProduct(products.first, userId: userId);
  }

  Future<bool> verifyTransaction(PaymentProvider provider, String transactionId) async {
    final gateway = _gateways[provider];
    if (gateway == null) return false;
    
    return await gateway.verifyTransaction(transactionId);
  }

  Future<PaymentTransaction> refundTransaction(
    PaymentProvider provider,
    String transactionId, {
    double? amount,
  }) async {
    final gateway = _gateways[provider];
    if (gateway == null) {
      throw PaymentSecurityException(
        'Payment provider not configured',
        'PROVIDER_NOT_CONFIGURED'
      );
    }

    final transaction = await gateway.refundTransaction(transactionId, amount: amount);
    await _storeTransaction(transaction);
    _transactionController.add(transaction);

    return transaction;
  }

  Future<void> _storeTransaction(PaymentTransaction transaction) async {
    final key = 'transaction_${transaction.id}';
    await SecureStorage.saveSecure(key, json.encode(transaction.toJson()));
  }

  Future<PaymentTransaction?> getTransaction(String transactionId) async {
    final key = 'transaction_$transactionId';
    final data = await SecureStorage.readSecure(key);
    
    if (data != null) {
      return PaymentTransaction.fromJson(json.decode(data));
    }
    
    return null;
  }

  void dispose() {
    _transactionController.close();
    _iapManager.dispose();
  }
}

