class PCIComplianceValidator {
  static bool validateCardNumber(String cardNumber) {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 13 || cleaned.length > 19) return false;
    
    return _luhnCheck(cleaned);
  }

  static bool _luhnCheck(String cardNumber) {
    int sum = 0;
    bool alternate = false;
    
    for (int i = cardNumber.length - 1; i >= 0; i--) {
      int digit = int.parse(cardNumber[i]);
      
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      
      sum += digit;
      alternate = !alternate;
    }
    
    return sum % 10 == 0;
  }

  static bool validateCVV(String cvv) {
    return RegExp(r'^\d{3,4}$').hasMatch(cvv);
  }

  static bool validateExpiryDate(String expiry) {
    final parts = expiry.split('/');
    if (parts.length != 2) return false;
    
    final month = int.tryParse(parts[0]);
    final year = int.tryParse(parts[1]);
    
    if (month == null || year == null) return false;
    if (month < 1 || month > 12) return false;
    
    final now = DateTime.now();
    final expiryDate = DateTime(2000 + year, month);
    
    return expiryDate.isAfter(now);
  }

  static String maskCardNumber(String cardNumber) {
    if (cardNumber.length < 4) return cardNumber;
    final last4 = cardNumber.substring(cardNumber.length - 4);
    return '**** **** **** $last4';
  }
}

class FraudDetectionService {
  static Future<bool> analyzeTransaction({
    required String userId,
    required double amount,
    required String currency,
    required String deviceId,
  }) async {
    final riskScore = _calculateRiskScore(amount, currency);
    
    if (riskScore > 0.8) {
      return false;
    }
    
    return true;
  }

  static double _calculateRiskScore(double amount, String currency) {
    double score = 0.0;
    
    if (amount > 1000) score += 0.3;
    if (amount > 5000) score += 0.3;
    
    return score.clamp(0.0, 1.0);
  }
}